import express from "express";
import cookieParser from "cookie-parser";
import helmet from "helmet";
import morgan from "morgan";
import passport from "passport";
import { config } from "./config.js";
import authRoutes from "./routes/auth.js";
import propertyRoutes from "./routes/properties.js";
import evaluationRoutes from "./routes/evaluations.js";
import clientRoutes from "./routes/clients.js";
import gmailRoutes from "./routes/gmail.js";
import inboxRoutes from "./routes/inbox.js";

const app = express();

app.use(helmet());
app.use(morgan("dev"));
app.use(express.json());
app.use(cookieParser());
app.use(passport.initialize());

// Routes
app.use("/api/auth", authRoutes);
app.use("/api/properties", propertyRoutes);
app.use("/api/evaluations", evaluationRoutes);
app.use("/api/clients", clientRoutes);
app.use("/api/gmail", gmailRoutes);
app.use("/api/inbox", inboxRoutes);

// Health check
app.get("/api/health", (_req, res) => {
  res.json({ status: "ok" });
});

app.listen(config.port, () => {
  console.log(`API server running on http://localhost:${config.port}`);
});

import dotenv from "dotenv";
import path from "path";

dotenv.config({ path: path.resolve(__dirname, "../.env") });

export const config = {
  port: parseInt(process.env.PORT || "4000", 10),
  nodeEnv: process.env.NODE_ENV || "development",
  databaseUrl:
    process.env.DATABASE_URL ||
    "postgresql://propstealth:propstealth_dev@localhost:5432/propstealth",
  jwtSecret: process.env.JWT_SECRET || "dev-secret-change-me",
  google: {
    clientId: process.env.GOOGLE_CLIENT_ID || "",
    clientSecret: process.env.GOOGLE_CLIENT_SECRET || "",
    callbackUrl:
      process.env.GOOGLE_CALLBACK_URL ||
      "http://localhost:3000/api/auth/google/callback",
    gmailCallbackUrl:
      process.env.GMAIL_CALLBACK_URL ||
      "http://localhost:3000/api/gmail/callback",
  },
  cookieName: "propstealth_session",
  sessionMaxAge: 7 * 24 * 60 * 60 * 1000, // 7 days in ms
  anthropicApiKey: process.env.ANTHROPIC_API_KEY || "",
} as const;

CREATE TABLE IF NOT EXISTS agent_clients (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  agent_id      UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  owner_id      UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  created_at    TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(agent_id, owner_id)
);

CREATE INDEX idx_agent_clients_agent_id ON agent_clients(agent_id);
CREATE INDEX idx_agent_clients_owner_id ON agent_clients(owner_id);

CREATE TABLE IF NOT EXISTS invitations (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  agent_id      UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  email         VARCHAR(255) NOT NULL,
  name          VARCHAR(255) NOT NULL,
  message       TEXT,
  status        VARCHAR(20) NOT NULL DEFAULT 'pending'
                CHECK (status IN ('pending', 'accepted', 'expired')),
  created_at    TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX idx_invitations_agent_id ON invitations(agent_id);
CREATE INDEX idx_invitations_email ON invitations(email);

