2	import jwt from "jsonwebtoken";
3	import { config } from "../config.js";
4	import { JwtPayload } from "../types.js";
5	
6	// Augment Express.User (declared by @types/passport) so that req.user is
7	// typed as JwtPayload throughout the app when requireAuth is applied.
8	declare global {
9	  namespace Express {
10	    interface User extends JwtPayload {}
11	  }
12	}
13	
14	export function requireAuth(req: Request, res: Response, next: NextFunction) {
15	  const token = req.cookies[config.cookieName];
16	
17	  if (!token) {
18	    res.status(401).json({ error: "Not authenticated" });
19	    return;
20	  }
21	
22	  try {
23	    const payload = jwt.verify(token, config.jwtSecret) as JwtPayload;
24	    req.user = payload;
25	    next();
26	  } catch {
27	    res.status(401).json({ error: "Invalid or expired token" });
28	    return;
29	  }
30	}
