10	export function ClientCard({ client }: ClientCardProps) {
11	  return (
12	    <div className="border border-gray-200 rounded-lg overflow-hidden mb-2.5">
13	      {/* Header */}
14	      <div className="px-4 py-3 bg-gray-50 flex justify-between items-center">
