16	          {/* Avatar */}
17	          <div
18	            className={`w-8 h-8 rounded-full ${client.initialsBg} flex items-center justify-center`}
19	          >
20	            <span className={`text-xs font-semibold ${client.initialsColor}`}>
21	              {client.initials}
22	            </span>
23	          </div>
24	          {/* Name + property info */}
25	          <div>
26	            <p className="text-[13px] font-medium text-gray-900">{client.name}</p>
27	            <p className="text-[11px] text-gray-500">
28	              {client.properties.length} propert{client.properties.length === 1 ? "y" : "ies"}
29	              {client.vacancyCount > 0 ? ` · ${client.vacancyCount} vacant` : ""}
30	            </p>
31	          </div>
32	        </div>
33	        <div className="flex items-center gap-2">
34	          <StatusBadge variant={client.vacancyCount > 0 ? "vacant" : "all-occupied"}>
35	            {client.vacancyCount > 0 ? "Vacant" : "All Occupied"}
36	          </StatusBadge>
37	          <Link
38	            href={`/agent/clients/${client.id}`}
39	            className="text-[11px] text-brand"
40	          >
41	            View →
42	          </Link>
43	        </div>
44	      </div>
45	
46	      {/* Property list */}
47	      <div className="px-4">
48	        {client.properties.map((property, index) => {
49	          const baseAddress = property.address.split(",")[0];
50	          const propertyPipeline = pipelineTenants.filter((t) =>
51	            t.propertyAddress.startsWith(baseAddress)
52	          );
53	          const proposedCount = propertyPipeline.filter(
54	            (t) => t.status === "proposed"
55	          ).length;
56	          const evaluatingCount = propertyPipeline.filter(
57	            (t) => t.status === "evaluating"
58	          ).length;
59	
60	          return (
61	            <div
62	              key={property.id}
63	              className={`flex items-center justify-between py-2.5 ${
64	                index < client.properties.length - 1
65	                  ? "border-b border-gray-100"
66	                  : ""
67	              }`}
68	            >
69	              {/* Left: address + details */}
70	              <div>
71	                <p className="text-xs text-gray-900">
72	                  {property.address}
73	                  {property.unit ? `, ${property.unit}` : ""}
74	                </p>
75	                <p className="text-[10px] text-gray-500">
76	                  {property.beds}bd · {property.baths}ba · {property.city}
77	                </p>
78	              </div>
79	
