1171	
1172	```ts
1173	// POST /invitations — create a client invitation with magic-link token
1174	router.post("/invitations", requireAuth, async (req: Request, res: Response) => {
1175	  try {
1176	    const { userId, role } = req.user as JwtPayload;
1177	    if (role !== "agent") {
1178	      res.status(403).json({ error: "Only agents can invite clients" });
1179	      return;
1180	    }
1181	
1182	    const { name, email, message } = req.body;
1183	    if (!name || !email) {
1184	      res.status(400).json({ error: "name and email are required" });
1185	      return;
1186	    }
1187	
1188	    // Check for an existing pending invite from THIS agent for THIS email
1189	    const existing = await db.query(
1190	      "SELECT * FROM invitations WHERE agent_id = $1 AND email = $2 AND status = 'pending'",
1191	      [userId, email],
1192	    );
1193	    if (existing.rows.length > 0) {
1194	      res.status(409).json({ error: "Invitation already sent to this email" });
1195	      return;
1196	    }
1197	
1198	    // Already a linked client?
1199	    const existingUser = await db.query(
1200	      `SELECT u.id FROM users u
1201	       JOIN agent_clients ac ON ac.owner_id = u.id AND ac.agent_id = $1
1202	       WHERE u.email = $2`,
1203	      [userId, email],
1204	    );
1205	    if (existingUser.rows.length > 0) {
1206	      res.status(409).json({ error: "This user is already your client" });
1207	      return;
1208	    }
1209	
1210	    const token = generateInviteToken();
1211	    const expiresAt = inviteExpiry();
1212	
1213	    const result = await db.query(
1214	      `INSERT INTO invitations
1215	         (agent_id, email, name, message, invite_token, invite_token_expires_at)
1216	       VALUES ($1, $2, $3, $4, $5, $6)
1217	       RETURNING *`,
1218	      [userId, email, name, message || null, token, expiresAt],
1219	    );
1220	
1221	    // Auto-link if the user already exists as an owner — skip token, mark accepted
1222	    const ownerResult = await db.query(
1223	      "SELECT id FROM users WHERE email = $1 AND role = 'owner'",
1224	      [email],
1225	    );
1226	    if (ownerResult.rows.length > 0) {
1227	      await db.query(
1228	        `INSERT INTO agent_clients (agent_id, owner_id)
1229	         VALUES ($1, $2)
1230	         ON CONFLICT (agent_id, owner_id) DO NOTHING`,
1231	        [userId, ownerResult.rows[0].id],
1232	      );
1233	      await db.query(
1234	        `UPDATE invitations
1235	            SET status = 'accepted',
1236	                invite_consumed_at = NOW()
1237	          WHERE id = $1`,
1238	        [result.rows[0].id],
1239	      );
1240	      result.rows[0].status = "accepted";
1241	      result.rows[0].invite_consumed_at = new Date();
1242	    }
1243	
1244	    res.status(201).json({ invitation: result.rows[0] });
1245	  } catch (err) {
1246	    console.error("Create invitation error:", err);
1247	    res.status(500).json({ error: "Failed to create invitation" });
1248	  }
1249	});
